// Valida la URL y construye la URL final con la API key inyectada.
// Try/catch global garantiza que SIEMPRE devolvamos un item — n8n no
// puede dejar el webhook colgado sin respuesta.
try {
  const src = $input.first().json;
  const body = src.body || src;
  const urlIn = body && body.url;
  if (!urlIn || typeof urlIn !== 'string') {
    return [{ json: { ok: false, reason: 'invalid_input', detail: 'url requerida en body.url' } }];
  }
  if (!urlIn.startsWith('https://solar.googleapis.com/')) {
    return [{ json: { ok: false, reason: 'invalid_url', detail: 'url debe ser de solar.googleapis.com' } }];
  }
  let gkey = null;
  try { gkey = $env && $env.GOOGLE_API_KEY; } catch (_) { /* ignore */ }
  if (!gkey) {
    return [{ json: { ok: false, reason: 'missing_env', detail: 'GOOGLE_API_KEY no configurada en n8n (Railway → Variables)' } }];
  }
  // String manipulation pura — quita ?key=/&key= y agrega el actual
  const hashIdx = urlIn.indexOf('#');
  const urlNoHash = hashIdx >= 0 ? urlIn.slice(0, hashIdx) : urlIn;
  const qIdx = urlNoHash.indexOf('?');
  const base = qIdx >= 0 ? urlNoHash.slice(0, qIdx) : urlNoHash;
  const qs = qIdx >= 0 ? urlNoHash.slice(qIdx + 1) : '';
  const params = qs.split('&').filter(p => p && p.split('=')[0] !== 'key');
  params.push('key=' + encodeURIComponent(gkey));
  const finalUrl = base + '?' + params.join('&');
  return [{ json: { ok: true, finalUrl } }];
} catch (e) {
  return [{ json: { ok: false, reason: 'validate_exception', detail: String(e && e.message || e).slice(0, 300) } }];
}

// Convierte el binario descargado a base64 + maneja errores HTTP.
// Try/catch global → siempre devuelve item válido.
try {
  const item = $input.first();
  // Error de red en el HTTP Request
  if (item.json && item.json.error) {
    const e = item.json.error;
    return [{ json: {
      ok: false,
      reason: 'fetch_error',
      detail: ((e.statusCode || '') + ' ' + (e.message || e.description || '')).trim() || 'fetch falló sin detalle',
    } }];
  }
  // HTTP 4xx/5xx con cuerpo de error
  const sc = item.json && item.json.statusCode;
  if (sc && sc >= 400) {
    let bodyText = '';
    try {
      const b = item.json.body;
      if (b) bodyText = (typeof b === 'string' ? b : (Buffer.isBuffer(b) ? b.toString('utf8') : JSON.stringify(b))).slice(0, 400);
    } catch (_) {}
    return [{ json: {
      ok: false,
      reason: 'http_' + sc,
      detail: 'Google HTTP ' + sc + ': ' + (bodyText || 'sin cuerpo'),
    } }];
  }
  // Binario presente: convertir a base64
  const bin = item.binary && item.binary.data;
  if (!bin || !bin.data) {
    return [{ json: {
      ok: false,
      reason: 'no_binary',
      detail: 'sin binario. statusCode=' + (sc || 'n/a') + ', json keys=' + Object.keys(item.json || {}).join(','),
    } }];
  }
  return [{ json: {
    ok: true,
    base64: bin.data,
    mimeType: bin.mimeType || 'image/tiff',
    size: Number(bin.fileSize) || null,
  } }];
} catch (e) {
  return [{ json: { ok: false, reason: 'encode_exception', detail: String(e && e.message || e).slice(0, 300) } }];
}
